import React from "react";
import "../../node_modules/bulma/css/bulma.min.css";
import { Block, Box, Panel, Button, Form, Heading, Message, Section } from "react-bulma-components";
import { Event, getDiscordMessage } from "../util/types";
import { RESIDENT_DJS } from "../util/constants";

type Props = {
    event: Event
};

const DjList = () => {


    return <Section>
        <Box>
            <Block>
                { Object.entries(RESIDENT_DJS).map(([key, dj]) => <>
                        <p>
                            <h2>{dj.name}</h2>
                            <ul>
                                { dj.twitch_url ? <>
                                    <li><a href={dj.twitch_url}>{dj.twitch_url}</a></li>
                                </> : null }
                                { dj.vrcdn_url ? <>
                                    <li><a href={dj.twitch_url}>{dj.vrcdn_url}</a></li>
                                </> : null }
                            </ul>
                        </p>
                        <hr />
                    </>
                )}
            </Block>
        </Box>
    </Section>
};

export default DjList;
